parameters.jsCode:
// n8n Code node (Run Once for All Items)
// Goal: Sanitize HTML, extract metadata, and detect marketing signals.

// -------------------- CONFIGURATION --------------------

// List of domains known for sending bulk marketing/transactional emails
const MARKETING_DOMAINS = [
  'mailchimp.com', 'constantcontact.com', 'sendgrid.net', 'amazonses.com',
  'mailgun.org', 'postmarkapp.com', 'mandrillapp.com', 'sparkpostmail.com',
  'email.amazon.com', 'notifications.google.com', 'noreply.github.com',
  'bounce.linkedin.com', 'facebookmail.com', 'twitter.com', 'intercom-mail.com',
  'klaviyo.com'
];

// -------------------- HELPERS --------------------

// Extract clean email from "Name <user@example.com>" format
function extractFromEmail(e) {
  const fromRaw = e.From || e.from?.value?.[0]?.address || e.from || "";

  if (typeof fromRaw === "string") {
    const m = fromRaw.match(/<([^>]+)>/);
    return (m ? m[1] : fromRaw).trim().toLowerCase();
  }
  return String(fromRaw).trim().toLowerCase();
}

// Extract just the domain part (e.g., "gmail.com")
function extractDomain(email) {
  if (!email) return "";
  const parts = email.split("@");
  return parts.length > 1 ? parts[1].toLowerCase().trim() : "";
}

// Check if domain matches known bulk senders
function isMarketingDomain(domain) {
  return MARKETING_DOMAINS.some(md => domain === md || domain.endsWith('.' + md));
}

// Decode HTML entities (e.g., &amp; -> &)
function decodeHtmlEntities(str) {
  return String(str)
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

// Normalize URLs found in headers/body
function normalizeUrl(u) {
  if (!u) return "";
  return decodeHtmlEntities(String(u).trim().replace(/^<|>$/g, ""));
}

// Check for the robust "List-Unsubscribe" header
function parseListUnsubscribeHeader(e) {
  let raw = "";

  // Handle different object structures (Direct object vs Array of headers)
  if (e?.headers && !Array.isArray(e.headers)) {
    raw = e.headers["list-unsubscribe"] || e.headers["List-Unsubscribe"] || "";
  } else if (Array.isArray(e?.headers)) {
    raw = e.headers.find(x => x.name?.toLowerCase() === "list-unsubscribe")?.value || "";
  } else if (Array.isArray(e?.payload?.headers)) {
    raw = e.payload.headers.find(x => x.name?.toLowerCase() === "list-unsubscribe")?.value || "";
  }

  if (!raw) return { raw: "", links: [] };

  const links = new Set();
  const str = String(raw);

  // Extract URLs inside <...> or distinct http/mailto links
  let m;
  const angleRe = /<([^>]+)>/g;
  while ((m = angleRe.exec(str)) !== null) links.add(normalizeUrl(m[1]));

  const tokenRe = /(mailto:[^,\s>]+|https?:\/\/[^,\s>]+)/gi;
  while ((m = tokenRe.exec(str)) !== null) links.add(normalizeUrl(m[1]));

  return { raw: str, links: [...links] };
}

// Scrape body for "unsubscribe" or "preferences" links
function extractUnsubscribeLinksFromBody(htmlOrText) {
  if (!htmlOrText) return [];
  const s = String(htmlOrText);
  const out = new Set();

  const keywords = /unsubscribe|optout|opt-out|preferences|email-preferences/i;

  // Check href attributes
  let m;
  const hrefRe = /href=['"]([^'"]+)['"]/gi;
  while ((m = hrefRe.exec(s)) !== null) {
    const url = normalizeUrl(m[1]);
    if (keywords.test(url)) out.add(url);
  }

  // Check raw URLs
  const urlRe = /(https?:\/\/[^\s<>"']+)/gi;
  while ((m = urlRe.exec(s)) !== null) {
    const url = normalizeUrl(m[1]);
    if (keywords.test(url)) out.add(url);
  }

  return [...out].slice(0, 5);
}

// Convert HTML to clean text for AI processing
function cleanBody(input) {
  if (!input) return "";
  let text = String(input);

  if (/<[a-z][\s\S]*>/i.test(text)) {
    text = text
      .replace(/<\/?(br|p|div|li|tr|h1|h2|h3)>/gi, "\n") // Block elements to newlines
      .replace(/<style[\s\S]*?<\/style>/gi, "")         // Remove styles
      .replace(/<script[\s\S]*?<\/script>/gi, "")       // Remove scripts
      .replace(/<[^>]+>/g, "");                          // Remove remaining tags
  }

  return text
    .replace(/[\u200B-\u200D\uFEFF]/g, "") // Remove invisible chars
    .replace(/\n{3,}/g, "\n\n")            // Collapse multiple newlines
    .split(/--\s*$/m)[0]                   // Try to cut off signatures
    .trim();
}

function isNoReplyAddress(email) {
  const local = (email.split("@")[0] || "").toLowerCase();
  return /(^no-?reply$|^noreply$|^do-?not-?reply$)/i.test(local);
}

function getLinkMetrics(html) {
  if (!html) return { linkCount: 0, uniqueHosts: 0 };
  const linkRegex = /href=['"]https?:\/\/([^'"/\s>]+)/gi;
  const hosts = new Set();
  let m;
  while ((m = linkRegex.exec(html)) !== null) {
    hosts.add(String(m[1]).toLowerCase());
  }
  return { linkCount: hosts.size, uniqueHosts: hosts.size };
}

// -------------------- MAIN LOGIC --------------------

const emails = $input.all().map(i => i.json);
const records = [];

for (const e of emails) {
  // 1. Basic Metadata
  const fromEmail = extractFromEmail(e);
  const senderDomain = extractDomain(fromEmail);
  const rawLabels = e.labelIds || e.labels || e.metrics?.labels || [];
  const html = e.html || e.body?.html || "";
  const text = e.text || e.body?.text || "";

  // 2. Unsubscribe Detection
  const headerUnsub = parseListUnsubscribeHeader(e);
  const bodyUnsubLinks = extractUnsubscribeLinksFromBody(html || text);

  const allUnsubLinks = [...new Set([...headerUnsub.links, ...bodyUnsubLinks])];
  const hasUnsubscribe = allUnsubLinks.length > 0;
  const hasListUnsubscribeHeader = Boolean(headerUnsub.raw);

  // 3. Marketing Flag Construction
  const flags = [];

  // Flag 1: Explicit Header (Strongest Signal)
  if (hasListUnsubscribeHeader) {
    flags.push("Has List-Unsubscribe Header");
  }

  // Flag 2: Known Bulk Domain
  if (isMarketingDomain(senderDomain)) {
    flags.push(`Known Marketing Domain (${senderDomain})`);
  }

  // Flag 3: Gmail "Promotions" Label
  if (rawLabels.includes("CATEGORY_PROMOTIONS")) {
    flags.push("Gmail Category: Promotions");
  }

  // Flag 4: Unsubscribe Link + No-Reply (Weak signals combined)
  if (hasUnsubscribe && isNoReplyAddress(fromEmail)) {
    flags.push("Unsubscribe Link in Body + No-Reply Sender");
  }

  const isMarketingEmail = flags.length > 0;
  const marketingReason = isMarketingEmail ? flags.join(" | ") : "None";

  // 4. Clean Body & Metrics
  const cleanedBody = cleanBody(text || html || "").slice(0, 1500);
  const linkMetrics = getLinkMetrics(html);

  // 5. Output Construction
  records.push({
    json: {
      id: e.id,
      subject: e.subject || e.Subject || "(No Subject)",
      from: fromEmail,
      senderDomain,

      // Core Marketing Signals
      isMarketingEmail,
      marketingReason, // EXPLAINS WHY it is marketing

      // Content for downstream AI
      cleanedBody,

      // Raw metrics (kept for debugging or context)
      metrics: {
        labels: rawLabels,
        hasListUnsubscribeHeader,
        unsubscribeLinkCount: allUnsubLinks.length,
        isNoReplyAddress: isNoReplyAddress(fromEmail),
        linkCount: linkMetrics.linkCount,
        marketingFlags: flags
      }
    }
  });
}

return records;

