const successCount = $input.all().filter(item => !item.json.error).length;
const totalCount = $input.all().length;

return [{
  json: {
    message: `Successfully created ${successCount} out of ${totalCount} labels`,
    successCount,
    totalCount,
    timestamp: new Date().toISOString()
  }
}];

const errors = $input.all().filter(item => item.json.error);

return errors.map(item => ({
  json: {
    labelName: item.json.name || 'Unknown',
    error: item.json.error,
    timestamp: new Date().toISOString()
  }
}));
